import { logo } from "../assets/home";
import Container from "./Container";

export default function Footer() {
  return (
    <footer className="bg-[#212121] py-14 text-white">
      <Container>
        <div className="flex flex-col sm:flex-row items-center sm:items-center sm:text-left text-center gap-4 sm:gap-8">
          <img src={logo} alt="Damroo Components" className="w-60 h-30" />
          <div className="mt-4 sm:mt-0 text-sm text-[#BFBFC8] space-y-1 text-center sm:text-left">
            <p>Damroo Components</p>
            <p>
              Plot no 18, Gali No 1, Krishna Colony, Opposite Sector 25,
              Faridabad, Haryana - 121004
            </p>
            <p>Email: damroocomponents@gmail.com</p>
            <p>Phone: 7982587458 , 9449879100</p>
          </div>
        </div>
      </Container>
    </footer>
  );
}
